const express = require('express');
const stytch = require('stytch');

const app = express();
app.use(express.json());

const client = new stytch.Client({
  project_id: process.env.STYTCH_PROJECT_ID,
  secret: process.env.STYTCH_SECRET,
});

app.post('/login', async (req, res) => {
  const { telemetry_id } = req.body;

  if (!telemetry_id) {
    return res.status(400).json({ error: 'telemetry_id is required' });
  }

  try {
    const response = await client.fraud.fingerprint.lookup({
      telemetry_id,
    });

    const action = response.verdict.action;

    if (action === 'BLOCK') {
      return res.status(403).json({ error: 'Access denied' });
    } else if (action === 'CHALLENGE') {
      return res.status(401).json({ error: 'MFA required' });
    } else if (action === 'ALLOW') {
      return res.status(200).json({ message: 'Login successful' });
    } else {
      return res.status(500).json({ error: 'Unexpected verdict action' });
    }
  } catch (error) {
    console.error('Stytch API error:', error);
    return res.status(500).json({ error: 'Internal Server Error' });
  }
});

module.exports = app;

